    async def _handle_msg(self, pid: str, msg: Dict[str, Any]):
        t = msg.get("t")
        p = self.players.get(pid)
        if not p:
            return

        if t == "input":
            seq = int(msg.get("seq", p.seq_in))
            if seq < p.seq_in:
                return
            p.seq_in = seq
            p.last_input_ms = now_ms()

