    async def _tick_loop(self):
        dt = 1.0 / max(1, self.tick_rate)
        while not self._stop.is_set():
            t0 = time.perf_counter()

            ts = now_ms()
            stale_cutoff = ts - 15000
            to_drop: List[str] = []
            for pid, p in self.players.items():
                if p.last_input_ms < stale_cutoff:
                    to_drop.append(pid)
            for pid in to_drop:
                ws = self.sockets.get(pid)
                if ws:
                    try:
                        await ws.close(code=1001, reason="Timeout")
                    except Exception:
                        pass

            ping_echo = now_ms()
            ping_msg = json.dumps({"t": "ping", "echo": ping_echo, "time_ms": ping_echo})
            for pid, ws in list(self.sockets.items()):
                try:
                    await ws.send(ping_msg)
                except Exception:
                    pass

            elapsed = time.perf_counter() - t0
            sleep_for = dt - elapsed
            if sleep_for > 0:
                try:
                    await asyncio.sleep(sleep_for)
                except asyncio.CancelledError:
                    return

    async def _broadcast_loop(self):
        dt = 1.0 / max(1, self.state_rate)
        while not self._stop.is_set():
            t0 = time.perf_counter()
            await self._broadcast_full_state()
